(1, '2 型糖尿病', '消渴病', '内科', 'MODERATE', '以血浆葡萄糖水平升高为特征的代谢性疾病', '多饮、多食、多尿、体重减轻，口渴喜饮，小便频数', '[{"name":"肺热津伤"},{"name":"胃热炽盛"},{"name":"肾阴亏虚"}]', '["消渴方","玉液汤","六味地黄丸"]', '["天花粉","葛根","山药","黄芪","地黄"]', NOW(), NOW()),
