(4, '慢性胃炎', '胃脘痛', '内科', 'MILD', '指各种病因引起的胃黏膜慢性炎症', '胃脘疼痛、胀满、隐痛、烧心、嗳气、纳差', '[{"name":"肝胃不和"},{"name":"脾胃虚弱"},{"name":"胃阴不足"}]', '["柴胡疏肝散","香砂六君子汤","益胃汤"]', '["柴胡","白芍","白术","党参","麦冬"]', NOW(), NOW()),
(5, '失眠', '不寐', '内科', 'MILD', '以经常不能获得正常睡眠为特征的一类病证', '睡眠障碍，入睡困难，易醒，早醒，多梦，醒后乏力', '[{"name":"肝火扰心"},{"name":"痰热扰心"},{"name":"心脾两虚"}]', '["龙胆泻肝汤","黄连温胆汤","归脾汤"]', '["酸枣仁","柏子仁","远志","茯苓","合欢皮"]', NOW(), NOW());
